<template>
  <div>
    <el-table
      ref="tagtable"
      v-loading="loading"
      :data="tmpData"
      @selection-change="checkChange"
    >
      <el-table-column
        type="selection"
        width="55"
        :selectable="whereDisable"
      />
      
      <el-table-column
        prop="tag_id"
        label="id"
      />
      
      <el-table-column
        prop="tag_name"
        label="Tag內容"
      />

      <el-table-column
        prop="status_text"
        label="Tag狀態"
      />

      <el-table-column
        v-if="handleType=='view'"
        label="昵稱/手機號"
      >
        <template
          slot-scope="scope"
        >
          {{ scope.row.userInfo.nickname }}</br>{{ scope.row.userInfo.mobile }}
        </template>
      </el-table-column>

      <el-table-column
        v-if="handleType=='view'"
        prop="created_text"
        label="創建時間"
      />

      <el-table-column
        label="操作"
        width="160"
        align="center"
      >
        <template
          slot-scope="scope"
        >
          <el-button
            type="text"
            @click="auditNote(scope.row)"
          >
            {{ resetText(scope.row) }}
          </el-button>
        </template>
      </el-table-column>
    </el-table>
  </div>
</template>

<script>
export default {
  props: {
    tmpData: Array,
    handleType:String,
    loading:Boolean
  },
  data () {
    return {

    }
  },
  computed: {
    resetText (){
      return (row)=>{
        var text = '審核';
        if(row.status=='1'){
          text = '拒絕'
        }else if(row.status=='2'){
          text = '通過'
        }
        return text;
      }
    }
  },
  mounted () {
  },
  methods: {
    whereDisable (row){
      var disable = true;
      // if(row.status=='1'){
      //   disable = false;
      // }
      //console.log('row',row)
      return disable;
    },
    auditNote (row){
      var params = {
        id_set:[row.tag_id],
        auditdiff:false,
        aloneAuditType:row.status=='1'?'refuse':'pass'
      }
      this.$refs.tagtable.clearSelection();
      this.$refs.tagtable.toggleRowSelection(row);
      this.$emit('selectNotes',params)
    },
    checkChange (val){
      var checkList = [];
      var auditdiff = false;
      var status = null;
      val.forEach(item=>{
        checkList.push(item.tag_id);
        if(status==null){
          status = item.status;
        }else if(status!=item.status){
          auditdiff = true;
        }
      })

      var params = {
        id_set:checkList,
        auditdiff
      }
      this.$emit('selectNotes',params)
      //console.log('checkChange',checkList,auditdiff)
    }

  }
}
</script>
